# ============================================================
# Helper Functions (輔助函數)
# ============================================================

def get_decan_by_longitude(longitude: float) -> dict:
    """Given an ecliptic longitude (0-360), return the corresponding Decan dict.

    Parameters
    ----------
    longitude : float
        Ecliptic longitude in degrees, 0 ≤ longitude < 360.
        Values outside this range are normalised via modulo 360.

    Returns
    -------
    dict
        The matching entry from :data:`DECANS_DATA`.
    """
    longitude = longitude % 360.0
    index = int(longitude // 10)
    # Clamp to valid range (handles edge case of exactly 360.0)
    if index > 35:
        index = 35
    return DECANS_DATA[index]


def get_decan_by_sign_and_degree(sign_index: int, degree_in_sign: float) -> dict:
    """Given sign index (0=Aries … 11=Pisces) and degree within sign (0-30),
    return the corresponding Decan dict.

    Parameters
    ----------
    sign_index : int
        Zodiac sign index, 0 (Aries) through 11 (Pisces).
    degree_in_sign : float
        Degree within the sign, 0 ≤ degree_in_sign < 30.

    Returns
    -------
    dict
        The matching entry from :data:`DECANS_DATA`.

    Raises
    ------
    ValueError
        If *sign_index* is not in 0..11 or *degree_in_sign* is out of range.
    """
    if not 0 <= sign_index <= 11:
        raise ValueError(f"sign_index must be 0-11, got {sign_index}")
    if not 0.0 <= degree_in_sign < 30.0:
        raise ValueError(
            f"degree_in_sign must be >= 0 and < 30, got {degree_in_sign}"
        )
    decan_offset = int(degree_in_sign // 10)  # 0, 1, or 2
    index = sign_index * 3 + decan_offset
    return DECANS_DATA[index]

